@app.route('/add_user', methods=['POST'])
def add_user():
    logger.info("Serving /add_user POST request.")
    # Request body will be captured because ELASTIC_APM_CAPTURE_BODY is 'all'
    data = flask.request.get_json()
    if not data or not data.get('username') or not data.get('email'):
        return flask.jsonify({"error": "Username and email are required"}), 400

    username = data['username']
    email = data['email']

    existing_user = User.query.filter_by(username=username).first()
    if existing_user:
        return flask.jsonify({"error": "User with this username already exists"}), 409

    new_user = User(username=username, email=email)
    db.session.add(new_user)
    db.session.commit() # This commit will be captured as a DB transaction

    simulate_work(0.03)
    perform_internal_logic(f"new user: {username}") # Another custom span

    return flask.jsonify({"message": "User added successfully", "id": new_user.id}), 201

